import React, { useState } from "react";
import Login from "./pages/Login";
import Register from "./pages/Register";
import Home from "./pages/Home";
import ProductsCard from "./pages/ProductsCard";
import Header from "./Component/Header";
import Footer from "./Component/Footer";

function App() {
  const [token, setToken] = useState(
    localStorage.getItem("token")
  );

  const [role, setRole] = useState(
    localStorage.getItem("role")
  );

  const [page, setPage] = useState("login");

  const logout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("role");
    localStorage.removeItem("userId");
    localStorage.removeItem("name");
    setToken(null);
    setRole(null);
    setPage("login");
  };

  const [view, setView] = useState(
    role === "admin" ? "dashboard" : "products"
  );

  return (
    <>
      {!token ? (
        page === "login" ? (
          <Login
            setToken={setToken}
            setPage={setPage}
            setRole={setRole}
          />
        ) : (
          <Register setPage={setPage} />
        )
      ) : (
        <div>
          <Header siteName="IntellMeet" role={role} logout={logout} view={view} setView={setView} />

          <main>
            {role === "admin" && view === "dashboard" && (
              <Home logout={logout} setView={setView} />
            )}

            {view === "products" && (
              <ProductsCard logout={logout} setView={setView} />
            )}
          </main>

          <Footer />
        </div>
      )}
    </>
  );
}

export default App;
